INSERT INTO "PUBLIC"."CONCERTS" VALUES
(TRUE, 10, TRUE, DATE '2024-06-21', 195, 3, TRUE, 85.00, FALSE, 10, 5, 10, 44, TRUE, 210.00, 320.00, 10, 9, 1, TIMESTAMP '2026-06-25 13:28:07.016387', 1, TIMESTAMP '2026-06-25 13:28:07.016387', 'London', 'UK', 'Mia, Hanna, Ema (all swifties since debut)', 'All Too Well (10 Minute Version)', 'Taylor Swift', 'Cathartic, generational, surreal, friendship bracelets traded', 'The Eras Tour', 'Wembley Stadium', 'Paramore', 'The Folklore set under the moss-covered cabin. The whole stadium silent then erupting.', U&'Worth every cent of the \20ac210 + travel. Wore the bejeweled outfit. Cried 4 times. Best show of my life.', '44 songs across 10 eras, surprise songs: Maroon (acoustic) + The Manuscript. The 1989 set was peak.', 'POP', 'INDIE_POP', 'STADIUM_TOUR', 'STADIUM', 'SEATED_FLOOR'),
(TRUE, 10, TRUE, DATE '2024-03-12', 115, 2, FALSE, 40.00, FALSE, 10, 5, 9, 22, TRUE, 75.00, 60.00, 10, 9, 1, TIMESTAMP '2026-06-25 13:28:07.027386', 2, TIMESTAMP '2026-06-25 13:28:07.027386', 'London', 'UK', 'Solo (queued 14 hours)', 'About You', 'The 1975', 'Theatrical, melancholy, intoxicating, fan-projection', 'Still... At Their Very Best', 'O2 Academy Brixton', 'Holly Humberstone', 'About You finale with confetti drop. Matty went off-script for two minutes. The set room with the TV.', 'Queued from 6am to get barricade. Worth it. Made friends in line.', 'The whole ''house'' set design is genius. I''m In Love With You was unhinged in the best way.', 'INDIE_POP', 'ALT_ROCK', 'ARENA_TOUR', 'LARGE_VENUE', 'BARRICADE'),
(FALSE, 9, FALSE, DATE '2024-09-08', 95, 2, TRUE, 35.00, FALSE, 8, 5, 10, 18, TRUE, 55.00, 40.00, 9, 10, 1, TIMESTAMP '2026-06-25 13:28:07.029386', 3, TIMESTAMP '2026-06-25 13:28:07.029386', 'London', 'UK', 'Pol (his first big indie show)', 'I Know The End', 'Phoebe Bridgers', 'Sad girl autumn, cathartic scream, communal grief', 'Reunion Tour', 'Alexandra Palace', 'MUNA, Christian Lee Hutson', 'Everyone screaming the I Know The End outro. Cathartic doesn''t begin to cover it.', 'MUNA were unreal too. Bought the Skeleton tour tee.', 'Full Punisher in order + Boygenius reunion encore with Lucy and Julien.', 'INDIE_ROCK', 'INDIE_POP', 'ARENA_TOUR', 'LARGE_VENUE', 'GENERAL_ADMISSION'),
(FALSE, 10, TRUE, DATE '2023-11-04', 165, 0, TRUE, 0.00, TRUE, 10, 5, 9, 28, FALSE, 90.00, 30.00, 10, 9, 1, TIMESTAMP '2026-06-25 13:28:07.031386', 4, TIMESTAMP '2026-06-25 13:28:07.031386', 'London', 'UK', 'Jake, Hanna, two strangers we met in the smoking area', 'Marea (we''ve lost dancing)', 'Fred again..', 'Euphoric, transcendent, phones-locked-up, full body sweat', 'Boiler Room x ConcertCrew', 'Printworks', 'Skrillex (b2b set)', 'The Skrillex b2b. Fred dropped Rumble unannounced. The whole crowd lost it.', 'Phone-free shows are how concerts should be. Found tickets day-of via the secret announce.', 'Yondr pouches at door. Best decision. Nobody filmed, everyone DANCED.', 'ELECTRONIC', 'HOUSE', 'SECRET_SHOW', 'LARGE_VENUE', 'STANDING_ONLY'),
(TRUE, 10, TRUE, DATE '2024-06-26', 140, 2, TRUE, 120.00, FALSE, 10, 5, 9, 20, FALSE, 180.00, 950.00, 10, 10, 1, TIMESTAMP '2026-06-25 13:28:07.033387', 5, TIMESTAMP '2026-06-25 13:28:07.033387', 'Tokyo', 'Japan', 'Ema (we flew to Tokyo for this)', 'Super Shy', 'NewJeans', 'Y2K kawaii, lightstick ocean, bunnies forever, jet-lagged but powering through', 'Bunnies Camp Tour', 'Tokyo Dome', NULL, 'The ETA stage with the entire dome in sync with the lightsticks.', 'Worth the flight. The Tokyo Dome lightstick coordination is unmatched.', 'Ditto + Hype Boy back-to-back was the killer combo. New choreography for Bubble Gum.', 'KPOP', 'POP', 'ARENA_TOUR', 'STADIUM', 'SEATED_FLOOR'),
(TRUE, 10, FALSE, DATE '2023-08-20', 75, 1, TRUE, 45.00, FALSE, 8, 5, 10, 14, TRUE, 75.00, 25.00, 10, 10, 1, TIMESTAMP '2026-06-25 13:28:07.034387', 6, TIMESTAMP '2026-06-25 13:28:07.034387', 'London', 'UK', 'Mia, Hanna, three other queer girls we met in line', 'Not Strong Enough', 'boygenius', 'Sapphic awakening, golden hour cry, friendship trio worship, communal', 'the rest tour', 'Gunnersbury Park', 'Ethel Cain, Muna', 'The three of them harmonizing on Letter To An Old Poet at golden hour.', 'Best summer afternoon of my life. Ethel Cain Preacher live = transcendent.', 'Full the record album + selections from the rest EP. Ethel Cain opener stole hearts.', 'INDIE_ROCK', 'INDIE_POP', 'FESTIVAL_SET', 'FESTIVAL_FIELD', 'FESTIVAL_FIELD');         
INSERT INTO "PUBLIC"."CONCERTS" VALUES
(FALSE, 8, FALSE, DATE '2024-04-18', 85, 2, FALSE, 28.00, TRUE, 10, 5, 10, 20, TRUE, 65.00, 18.00, 9, 10, 1, TIMESTAMP '2026-06-25 13:28:07.035385', 7, TIMESTAMP '2026-06-25 13:28:07.035385', 'London', 'UK', 'Solo (intentionally)', 'Last Words of a Shooting Star', 'Mitski', 'Theatrical, devastating, intimate-despite-2000-people, intentional', 'The Land Is Inhospitable Tour', 'Eventim Apollo', 'Madison Cunningham', 'Her choreographed movements during Washing Machine Heart. Visual poetry.', 'Went alone on purpose. Cried discreetly during ''I Bet on Losing Dogs''. Healing.', 'Phone-free policy was perfect. Mitski''s stage direction is unparalleled.', 'INDIE_ROCK', 'INDIE_POP', 'ARENA_TOUR', 'MID_VENUE', 'SEATED_LOWER'),
(TRUE, 10, TRUE, DATE '2024-07-05', 80, 0, FALSE, 50.00, FALSE, 9, 5, 10, 16, FALSE, 95.00, 25.00, 10, 9, 1, TIMESTAMP '2026-06-25 13:28:07.036385', 8, TIMESTAMP '2026-06-25 13:28:07.036385', 'London', 'UK', 'Mia, Jake, Pol (we all wore brat-green)', '365', 'Charli XCX', 'Brat summer, sweaty, lime-green tribalism, hyperpop euphoria', 'Brat Tour', 'Crystal Palace Park', 'Shygirl, A. G. Cook DJ set', 'Apple turned the entire field into one choreographed flash mob. Brat summer peaked.', 'This show defined the summer of 2024. Worth it just for the Apple choreo viral moment.', 'Full Brat in order + Track 10 + Vroom Vroom encore. A.G. Cook B2B was insane.', 'HYPERPOP', 'ELECTRONIC', 'FESTIVAL_SET', 'FESTIVAL_FIELD', 'FESTIVAL_FIELD'),
(FALSE, 10, TRUE, DATE '2024-05-23', 130, 1, TRUE, 0.00, FALSE, 10, 4, 8, 32, FALSE, 145.00, 280.00, 9, 8, 1, TIMESTAMP '2026-06-25 13:28:07.037386', 9, TIMESTAMP '2026-06-25 13:28:07.037386', 'Madrid', 'Spain', 'Hanna + her cousins from Madrid', 'Yo Perreo Sola', 'Bad Bunny', 'Perreo, latin trap takeover, summer in Madrid, sweaty euphoria', 'Most Wanted Tour', 'Estadio Olimpico', NULL, 'The mechanical bull rising during Monaco. Latin trap stadium chaos.', 'Stadium upper section is sketchy but the production made up for it. Hanna''s family fed us paella.', 'Heavy on nadie sabe + un verano sin ti cuts. Saturno trap deep cuts too.', 'RAP', 'HIP_HOP', 'STADIUM_TOUR', 'STADIUM', 'SEATED_UPPER'),
(FALSE, 7, FALSE, DATE '2024-02-09', 105, 1, TRUE, 25.00, FALSE, 7, 5, 9, 15, TRUE, 32.00, 12.00, 10, 10, 1, TIMESTAMP '2026-06-25 13:28:07.038386', 10, TIMESTAMP '2026-06-25 13:28:07.038386', 'London', 'UK', 'Pol (we both wept)', 'Turbines/Pigs', 'Black Country, New Road', 'Cathartic chamber-rock, post-Isaac era, communal silence, devastating', 'Live at Bush Hall Tour', 'EartH Hackney', 'Caroline', 'The brass section during The Boy. Post-rock at its absolute peak.', 'BCNR live is a different band than the records. The new era is even better. Bought the vinyl.', 'Almost entirely new material from Forever Howlong. Live At Bush Hall was incredible too.', 'INDIE_ROCK', 'FOLK', 'INTIMATE_VENUE', 'SMALL_CLUB', 'SEATED_FLOOR'); 
